sys_script_fix.script:
(function() {
    var today = new GlideDateTime(); // or use GlideDate() if the field is Date only
    gs.print('Today is: ' + today.getDisplayValue());

    var gr = new GlideRecord("u_appointment");
    gr.addQuery('u_appointment_date', '<', today);
    gr.addQuery('u_status', '!=', 'Cancelled');
    gr.query();

    var count = 0;
    while (gr.next()) {
        gr.u_status = 'Cancelled';
        gr.update();
        gs.print('✅ Cancelled appointment on: ' + gr.u_appointment_date.getDisplayValue());
        count++;
    }

    if (count == 0) {
        gs.print("❌ No overdue appointments found.");
    } else {
        gs.print("✅ Total appointments cancelled: " + count);}
})();
